class Solution:
    def maxXor(self, nums, k: int) -> int:
        # Independent approach: literal O(n^2) scan of every subarray, tracking
        # its running max/min/XOR directly, with no trie or two-pointer window
        # at all -- exercised only on the small literal inputs this oracle sees.
        n = len(nums)
        best = 0
        for i in range(n):
            mx = mn = nums[i]
            xr = nums[i]
            if mx - mn <= k:
                best = max(best, xr)
            for j in range(i + 1, n):
                mx = max(mx, nums[j])
                mn = min(mn, nums[j])
                xr ^= nums[j]
                if mx - mn <= k:
                    best = max(best, xr)
        return best

