from collections import deque

_BITS = 15


class _TrieNode:
    __slots__ = ('children', 'count')

    def __init__(self):
        self.children = [None, None]
        self.count = 0


class _Trie:
    def __init__(self):
        self.root = _TrieNode()

    def insert(self, val):
        node = self.root
        for b in range(_BITS - 1, -1, -1):
            bit = (val >> b) & 1
            if node.children[bit] is None:
                node.children[bit] = _TrieNode()
            node = node.children[bit]
            node.count += 1

    def remove(self, val):
        node = self.root
        for b in range(_BITS - 1, -1, -1):
            bit = (val >> b) & 1
            node = node.children[bit]
            node.count -= 1

    def query_max(self, target):
        node = self.root
        result = 0
        for b in range(_BITS - 1, -1, -1):
            bit = (target >> b) & 1
            want = 1 - bit
            if node.children[want] is not None and node.children[want].count > 0:
                result |= (1 << b)
                node = node.children[want]
            else:
                node = node.children[bit]
        return result


class Solution:
    def maxXor(self, nums, k: int) -> int:
        n = len(nums)
        prefix = [0] * (n + 1)
        for i in range(n):
            prefix[i + 1] = prefix[i] ^ nums[i]
        trie = _Trie()
        max_deque = deque()
        min_deque = deque()
        l = 0
        ans = 0
        for r in range(n):
            while max_deque and nums[max_deque[-1]] <= nums[r]:
                max_deque.pop()
            max_deque.append(r)
            while min_deque and nums[min_deque[-1]] >= nums[r]:
                min_deque.pop()
            min_deque.append(r)
            while nums[max_deque[0]] - nums[min_deque[0]] > k:
                if max_deque[0] == l:
                    max_deque.popleft()
                if min_deque[0] == l:
                    min_deque.popleft()
                trie.remove(prefix[l])
                l += 1
            trie.insert(prefix[r])
            ans = max(ans, trie.query_max(prefix[r + 1]))
        return ans

