var maxXor = function(nums, k) {
    const BITS = 15;
    function makeNode() { return { children: [null, null], count: 0 }; }
    const root = makeNode();
    function insert(val) {
        let node = root;
        for (let b = BITS - 1; b >= 0; b--) {
            const bit = (val >> b) & 1;
            if (node.children[bit] === null) node.children[bit] = makeNode();
            node = node.children[bit];
            node.count += 1;
        }
    }
    function remove(val) {
        let node = root;
        for (let b = BITS - 1; b >= 0; b--) {
            const bit = (val >> b) & 1;
            node = node.children[bit];
            node.count -= 1;
        }
    }
    function queryMax(target) {
        let node = root;
        let result = 0;
        for (let b = BITS - 1; b >= 0; b--) {
            const bit = (target >> b) & 1;
            const want = 1 - bit;
            if (node.children[want] !== null && node.children[want].count > 0) {
                result |= (1 << b);
                node = node.children[want];
            } else {
                node = node.children[bit];
            }
        }
        return result;
    }

    const n = nums.length;
    const prefix = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) prefix[i + 1] = prefix[i] ^ nums[i];
    const maxDeque = [];
    const minDeque = [];
    let l = 0;
    let ans = 0;
    for (let r = 0; r < n; r++) {
        while (maxDeque.length && nums[maxDeque[maxDeque.length - 1]] <= nums[r]) maxDeque.pop();
        maxDeque.push(r);
        while (minDeque.length && nums[minDeque[minDeque.length - 1]] >= nums[r]) minDeque.pop();
        minDeque.push(r);
        while (nums[maxDeque[0]] - nums[minDeque[0]] > k) {
            if (maxDeque[0] === l) maxDeque.shift();
            if (minDeque[0] === l) minDeque.shift();
            remove(prefix[l]);
            l += 1;
        }
        insert(prefix[r]);
        ans = Math.max(ans, queryMax(prefix[r + 1]));
    }
    return ans;
};
